BeginPackage["ONdata`"]


(* ::Section::Closed:: *)
(*Function information*)


DeltaE::usage = "DeltaE[Op] gives the scaling dimension of Op in the d = 4 - e expansion." 


DeltaN::usage = "DeltaN[Op] gives the scaling dimension of Op in the large N expansion for mu = d/2." 


DeltaZ::usage = "DeltaZ[Op] gives the scaling dimension of Op in the non-linear sigma model in the 2+e expansion. This is only implemented for a limited set of operators." 


ValueE::usage = "ValueE[q] gives the value of the quantity q in the d = 4 - e expansion." 


ValueN::usage = "ValueN[q] gives the value of the quantity q in the large N expansion for mu = d/2." 


ValueZ::usage = "ValueZ[q] gives the value of the quantity q in the non-linear sigma model in the 2+e expansion. This is only implemented for a limited set of quantities." 


z::usage = "z[i] denotes Riemann's zeta values Zeta[i]."


mz::usage = "mz[i,j,...] denotes the multiple zeta values. Use multiZetaSub to replace by numerical values."


P711::usage = "P711 denotes the constant \!\(\*SubscriptBox[\(P\), \(7, 11\)]\), also implemented as const[4]."


Op::usage = "Op[R,l,i] denotes the operator in the representation R and spin l with \!\(\*SuperscriptBox[\(i\), \(th\)]\) lowest scaling dimension."


ord::usage = "The term ord \!\(\*SuperscriptBox[\(x\), \(k\)]\) denotes not computed resuts at O(\!\(\*SuperscriptBox[\(x\), \(k\)]\))."


e::usage = "e denotes \[Epsilon] in the d = 4 - \[Epsilon] expansion, and \!\(\*OverscriptBox[\(\[Epsilon]\), \(~\)]\) in the non-linear sigma model in the d = 2 + \!\(\*OverscriptBox[\(\[Epsilon]\), \(~\)]\) expansion"


n::usage = "n denotes the parameter n of the O(n) global symmetry."


mu::usage = "mu denotes d/2 for the spacetime dimension d."


OpeE::usage = "OpeE[Op1,Op2,Op3] gives the squared OPE coefficient \!\(\*SuperscriptBox[SubscriptBox[\(\[Lambda]\), \(Op1, Op2, Op3\)], \(2\)]\) in the d = 4 - e expansion. OpeE[Op] gives the squared OPE coefficient \!\(\*SuperscriptBox[SubscriptBox[\(\[Lambda]\), \(\[Phi], \[Phi], Op\)], \(2\)]\) of Op in the \[Phi]*\[Phi] OPE, in the d = 4 - e expansion." 


OpeN::usage = "OpeN[Op] gives the squared OPE coefficient \!\(\*SuperscriptBox[SubscriptBox[\(c\), \(Op1, Op2, Op3\)], \(2\)]\) in the large N expansion for mu = d/2. OpeN[Op] gives the squared OPE coefficient \!\(\*SuperscriptBox[SubscriptBox[\(\[Lambda]\), \(\[Phi], \[Phi], Op\)], \(2\)]\)  of Op in the \[Phi]*\[Phi] OPE, in the large N expansion for mu = d/2." 


(* ::Subsection:: *)
(*Other observables*)


CT::usage = "\!\(\*SubscriptBox[\(C\), \(T\)]\)/\!\(\*SubscriptBox[\(C\), \(T, free\)]\)."


CJ::usage = "\!\(\*SubscriptBox[\(C\), \(J\)]\)/\!\(\*SubscriptBox[\(C\), \(J, free\)]\)."


alpha::usage = "Critical exponent \[Alpha]."


beta::usage = "Critical exponent \[Beta]."


gamma::usage = "Critical exponent \[Gamma]."


delta::usage = "Critical exponent \[Delta]."


eta::usage = "Critical exponent \[Eta]."


nu::usage = "Critical exponent \[Nu]."


phic::usage = "Critical exponent \!\(\*SubscriptBox[\(\[Phi]\), \(c\)]\)."


omega::usage = "Critical exponent \[Omega]."


intercept::usage = "intercept[R] denotes the Regge intercept in the representation R."


RGbeta::usage = "RGbeta[g] denotes the beta function"


RGm2::usage = "RGm2[g] denotes the anomalous dimension of \!\(\*SuperscriptBox[\(\[Phi]\), \(2\)]\) "


RGgamma::usage = "RGgamma[g] denotes the anomaluos dimension of \[Phi]"


criticalCoupling::usage = "criticalCoupling denotes the critical coupling as a function of e"


crossingM::usage = "crossingM[\!\(\*SubscriptBox[\(R\), \(1\)]\),\!\(\*SubscriptBox[\(R\), \(2\)]\),\!\(\*SubscriptBox[\(R\), \(3\)]\),\!\(\*SubscriptBox[\(R\), \(4\)]\)] gives basis of exchanged irreps and the corresponding crossing matrix."


(* ::Subsection::Closed:: *)
(*Representations*)


S::usage = "Irrep S - singlet."


V::usage = "Irrep V - vector."


T::usage = "Irrep T - rank 2 traceless symmetric tensor."


A::usage = "Irrep A - rank 2 antisymmetric tensor."


Tm::usage = "Tm[m]: Irrep \!\(\*SubscriptBox[\(T\), \(m\)]\) - rank m traceless symmetric tensor."


A3::usage = "Irrep \!\(\*SubscriptBox[\(A\), \(3\)]\) - rank 3 antisymmetric tensor."


Hm::usage = "Hm[m] Irrep \!\(\*SubscriptBox[\(H\), \(m\)]\) - hook representation with m boxes."


B4::usage = "Irrep \!\(\*SubscriptBox[\(B\), \(4\)]\) - box representation with 4 boxes."


YT::usage = "YT[{\!\(\*SubscriptBox[\(r\), \(1\)]\),\!\(\*SubscriptBox[\(r\), \(2\)]\),...}] gives the O(N) irrep with Young tableau with rows of length \!\(\*SubscriptBox[\(r\), \(1\)]\), \!\(\*SubscriptBox[\(r\), \(2\)]\), ..."


