(* ::Section::Closed:: *)
(*Constants*)


const::usage = "const[i] is a placeholder for a numerical constant."


multiZetaSub::usage = "Gives substitutions for the multiple Zeta values."


constVal::usage = "constVal[i] gives the numerical value of const[i]."


eta3::usage = "eta3[mu] denotes the order \!\(\*SuperscriptBox[\(N\), \(-3\)]\) correction to the critical exponent \[Eta], only implemented for particular values of mu."


eta1half::usage = "Denotes the order 1/N anomalous dimension of the operator Op[V,0,1]=\[Phi] in the large N expansion. This equals half of the order 1/N term in the critical exponent \[Eta]."


Begin["`Private`"]


Tm[0]=S;


Tm[1]=V;


Tm[2]=T;


Hm[2]=A;


constVal[1]=0.037707672984847544011304781285219639854685927865670715228744532939;


constVal[2]=0.00841966850309633242396857959034671994551640863209043385603136268;


constVal[3]=0.00078920980171319542876056500105769563342484426303614603490268275;


constVal[4]=200.35756642927544697;


constVal[5]=\[Minus]15.830116;


multiZetaSub={mz[5,3]->constVal[1],mz[7,3]->constVal[2],mz[5,3,3]->constVal[3],P711->constVal[4]};


eta1half=((-2+mu) Gamma[-1+2 mu])/(Gamma[1-mu] Gamma[mu]^2 Gamma[1+mu]);


YT[{}]=S;


YT[{m_}]=Tm[m];


YT[{m_,1}]=Hm[m+1];


YT[{2,2}]=B4;


YT[{1,1,1}]=A3;


Op[r_,{l_},i_]=Op[r,l,i];


